// src/pages/DashboardPage.js
import React, { useState, useCallback } from 'react';
import { Responsive, WidthProvider } from 'react-grid-layout';
import { useDashboard } from '../context/DashboardContext';
import { useOrders }    from '../context/OrdersContext';
import { useToast }     from '../context/ToastContext';
import Topbar           from '../components/layout/Topbar';
import WidgetRenderer   from '../components/widgets/WidgetRenderer';
import WidgetPanel      from '../components/modals/WidgetPanel';
import { fmtINR }       from '../utils/constants';
import 'react-grid-layout/css/styles.css';
import 'react-resizable/css/styles.css';

const RGL  = WidthProvider(Responsive);
const BP   = {lg:1200, md:996, sm:768, xs:480};
const COLS = {lg:12,   md:8,   sm:6,   xs:4};

// Widget library items for the left panel (matches Figma)
const WIDGET_LIBRARY = [
  { section:'Charts', items:[
    {type:'bar',    label:'Bar Chart',    icon:'▐', color:'#10b981'},
    {type:'line',   label:'Line Chart',   icon:'∿', color:'#6366f1'},
    {type:'pie',    label:'Pie Chart',    icon:'◔', color:'#f59e0b'},
    {type:'area',   label:'Area Chart',   icon:'◓', color:'#06b6d4'},
    {type:'scatter',label:'Scatter Plot', icon:'⋰', color:'#f43f5e'},
  ]},
  { section:'Tables', items:[
    {type:'table',  label:'Table',        icon:'⊞', color:'#8b5cf6'},
  ]},
  { section:'KPIs', items:[
    {type:'kpi',    label:'KPI Value',    icon:'◉', color:'#ec4899'},
  ]},
];

const STAT_CFG = [
  {label:'Total Revenue',  calc:o=>o.reduce((s,x)=>s+(x.totalAmount||0),0), fmt:fmtINR,   color:'#10b981', icon:'₹', bg:'#f0fdf4'},
  {label:'Total Orders',   calc:o=>o.length,                                 fmt:v=>v,     color:'#6366f1', icon:'⊞', bg:'#eef2ff'},
  {label:'Completed',      calc:o=>o.filter(x=>x.status==='Completed').length,fmt:v=>v,    color:'#06b6d4', icon:'✓', bg:'#ecfeff'},
  {label:'In Progress',    calc:o=>o.filter(x=>x.status==='In progress').length,fmt:v=>v,  color:'#f59e0b', icon:'⟳', bg:'#fffbeb'},
];

export default function DashboardPage() {
  const {widgets,layouts,editMode,saved,addWidget,updateWidget,delWidget,setLayouts,toggleEdit,save}=useDashboard();
  const {orders}  = useOrders();
  const {add}     = useToast();
  const [panel,    setPanel]    = useState(null);
  const [saving,   setSaving]   = useState(false);
  const [delId,    setDelId]    = useState(null);
  const [dateRange,setDateRange]= useState('All time');
  const [showPreview, setShowPreview] = useState(null); // preview on hover

  const handleLayout = useCallback((_,all) => setLayouts(all), [setLayouts]);

  async function handleSave() {
    setSaving(true);
    try { await save(); add('Dashboard saved!','success'); toggleEdit(); }
    catch { add('Save failed','error'); }
    finally { setSaving(false); }
  }

  function quickAdd(type) {
    addWidget({ type, title: type.charAt(0).toUpperCase()+type.slice(1)+' Chart' });
    add('Widget added to canvas','success');
  }

  // ── Configure mode layout ──────────────────────────────────────────────────
  if (editMode) {
    return (
      <div style={{display:'flex',flexDirection:'column',height:'100vh'}}>
        {/* Configure Topbar */}
        <div style={{height:52,background:'#fff',borderBottom:'1px solid var(--border)',display:'flex',alignItems:'center',padding:'0 20px',gap:12,flexShrink:0}}>
          <button className="btn btn-ghost btn-sm" onClick={toggleEdit} style={{gap:8}}>
            ← Back
          </button>
          <div style={{width:1,height:20,background:'var(--border)'}}/>
          <div>
            <div style={{fontSize:13,fontWeight:700,fontFamily:'var(--ff-h)'}}>Configure dashboard</div>
            <div style={{fontSize:11,color:'var(--t3)'}}>Configure your dashboard to start viewing analytics</div>
          </div>
          <div style={{marginLeft:'auto',display:'flex',gap:8}}>
            <button className="btn btn-ghost btn-sm" onClick={toggleEdit}>Cancel</button>
            <button className="btn btn-primary btn-sm" onClick={handleSave} disabled={saving}>
              {saving?<><span className="spinner"/>Saving…</>:'Save'}
            </button>
          </div>
        </div>

        <div style={{display:'flex',flex:1,overflow:'hidden'}}>
          {/* Widget Library Sidebar */}
          <div style={{width:180,flexShrink:0,background:'#fff',borderRight:'1px solid var(--border)',display:'flex',flexDirection:'column',overflow:'hidden'}}>
            {/* Date filter */}
            <div style={{padding:'14px 14px 10px',borderBottom:'1px solid var(--border)'}}>
              <div style={{fontSize:11,fontWeight:700,color:'var(--t3)',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:6}}>Show data for</div>
              <select value={dateRange} onChange={e=>setDateRange(e.target.value)} style={{width:'100%',padding:'7px 10px',border:'1px solid var(--border2)',borderRadius:'var(--r1)',fontSize:12,color:'var(--t1)',background:'#fff',outline:'none',cursor:'pointer',fontFamily:'var(--ff-b)'}}>
                {['All time','Today','This week','This month','This year'].map(d=><option key={d}>{d}</option>)}
              </select>
            </div>

            {/* Library */}
            <div style={{flex:1,overflow:'y-auto',padding:'10px 0'}}>
              <div style={{padding:'0 14px 8px',fontSize:11,fontWeight:700,color:'var(--t3)',textTransform:'uppercase',letterSpacing:'.06em'}}>Widget library</div>
              <div style={{padding:'0 12px',fontSize:11,color:'var(--t3)',marginBottom:10}}>Drag and drop your canvas</div>

              {WIDGET_LIBRARY.map(section=>(
                <div key={section.section}>
                  <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'8px 14px 4px',cursor:'pointer'}}>
                    <span style={{fontSize:11,fontWeight:700,color:'var(--t2)'}}>{section.section}</span>
                    <span style={{fontSize:10,color:'var(--t3)'}}>∧</span>
                  </div>
                  {section.items.map(item=>(
                    <button key={item.type}
                      draggable
                      onDragEnd={()=>quickAdd(item.type)}
                      onClick={()=>setPanel({type:item.type,isNew:true})}
                      style={{display:'flex',alignItems:'center',gap:8,padding:'7px 14px',width:'100%',background:'transparent',border:'none',cursor:'grab',fontSize:12,color:'var(--t1)',fontFamily:'var(--ff-b)',transition:'background .15s',userSelect:'none'}}
                      onMouseEnter={e=>e.currentTarget.style.background='var(--bg)'}
                      onMouseLeave={e=>e.currentTarget.style.background='transparent'}
                    >
                      <span style={{fontSize:8,color:'var(--t3)',display:'grid',gridTemplateColumns:'1fr 1fr',gap:1}}>{'⠿'}</span>
                      <div style={{width:18,height:18,borderRadius:4,background:`${item.color}18`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,color:item.color}}>
                        {item.icon}
                      </div>
                      <span>{item.label}</span>
                    </button>
                  ))}
                </div>
              ))}
            </div>
          </div>

          {/* Canvas */}
          <div style={{flex:1,overflow:'auto',background:'var(--bg)',padding:16,position:'relative'}}>
            {showPreview && (
              <div style={{position:'absolute',top:16,left:'50%',transform:'translateX(-50%)',zIndex:50,background:'#fff',border:'1px solid var(--border)',borderRadius:'var(--r3)',padding:20,minWidth:400,boxShadow:'var(--s3)'}}>
                <div style={{fontFamily:'var(--ff-h)',fontSize:14,fontWeight:700,marginBottom:12}}>{showPreview.label} Preview</div>
                <div style={{height:180,background:'var(--bg)',borderRadius:'var(--r2)',display:'flex',alignItems:'center',justifyContent:'center',color:'var(--t3)',fontSize:13}}>
                  Chart preview will render with real data
                </div>
              </div>
            )}

            {widgets.length===0 ? (
              <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(80px,1fr))',gap:6}}>
                {Array.from({length:130}).map((_,i)=>(
                  <div key={i} style={{height:32,background:'rgba(0,0,0,.04)',borderRadius:4}}/>
                ))}
              </div>
            ) : (
              <RGL layouts={layouts} breakpoints={BP} cols={COLS} rowHeight={60}
                isDraggable isResizable onLayoutChange={handleLayout}
                margin={[10,10]} containerPadding={[0,0]}>
                {widgets.map(w=>(
                  <div key={w.id} style={{background:'#fff',borderRadius:'var(--r2)',border:'2px solid rgba(99,102,241,.35)',overflow:'hidden',boxShadow:'0 0 0 2px rgba(99,102,241,.08)',cursor:'grab',position:'relative'}}>
                    <div style={{position:'absolute',top:4,right:4,display:'flex',gap:3,zIndex:10}}>
                      <button className="btn-icon" style={{width:22,height:22,fontSize:10}} onClick={()=>setPanel(w)}>⚙</button>
                      <button className="btn-icon btn-icon-danger" style={{width:22,height:22,fontSize:10}} onClick={()=>setDelId(w.id)}>✕</button>
                    </div>
                    <WidgetRenderer widget={w}/>
                  </div>
                ))}
              </RGL>
            )}
          </div>
        </div>

        {/* Widget Panel */}
        {panel&&(
          <>
            <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,.25)',zIndex:799}} onClick={()=>setPanel(null)}/>
            <WidgetPanel
              existing={panel.isNew?null:panel}
              onClose={()=>setPanel(null)}
              onSave={cfg=>{
                if(cfg.id){updateWidget(cfg);add('Widget updated','success');}
                else{addWidget(cfg);add('Widget added','success');}
                setPanel(null);
              }}
            />
          </>
        )}

        {delId&&(
          <div className="overlay">
            <div className="modal modal-sm">
              <div className="modal-hd"><h2>Remove Widget</h2><button className="btn-icon" onClick={()=>setDelId(null)}>✕</button></div>
              <div className="modal-body"><p style={{color:'var(--t2)',fontSize:14}}>Remove this widget from the dashboard?</p></div>
              <div className="modal-ft">
                <button className="btn btn-ghost" onClick={()=>setDelId(null)}>Cancel</button>
                <button className="btn btn-danger" onClick={()=>{delWidget(delId);setDelId(null);add('Widget removed','info');}}>Remove</button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  // ── View mode ──────────────────────────────────────────────────────────────
  return (
    <div style={{display:'flex',flexDirection:'column',height:'100vh'}}>
      <Topbar
        title="Dashboard"
        subtitle={`${widgets.length} widget${widgets.length!==1?'s':''} · View mode${!saved?' · Unsaved changes':''}`}
        actions={
          <div style={{display:'flex',gap:8}}>
            {!saved && <button className="btn btn-primary btn-sm" onClick={async()=>{setSaving(true);try{await save();add('Saved!','success');}finally{setSaving(false);}}} disabled={saving}>{saving?'Saving…':'Save'}</button>}
            <button className="btn btn-primary btn-sm" onClick={toggleEdit} style={{background:'var(--primary)',boxShadow:'none'}}>
              ⚙ Configure Dashboard
            </button>
          </div>
        }
      />

      <div style={{flex:1,overflow:'auto',padding:20,background:'var(--bg)'}}>
        {/* KPI Strip */}
        <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(160px,1fr))',gap:12,marginBottom:20}}>
          {STAT_CFG.map((s,i)=>{
            const val=s.calc(orders);
            return (
              <div key={s.label} className={`card fade-up d${i+1}`} style={{padding:'16px 18px',display:'flex',alignItems:'center',gap:14,transition:'var(--t)'}}>
                <div style={{width:42,height:42,borderRadius:12,background:s.bg,display:'flex',alignItems:'center',justifyContent:'center',fontSize:18,color:s.color,flexShrink:0}}>
                  {s.icon}
                </div>
                <div>
                  <div style={{fontSize:'clamp(16px,2vw,22px)',fontWeight:800,fontFamily:'var(--ff-h)',color:s.color,lineHeight:1.1}}>{s.fmt(val)}</div>
                  <div style={{fontSize:11,color:'var(--t3)',fontWeight:600,textTransform:'uppercase',letterSpacing:'.05em',marginTop:3}}>{s.label}</div>
                </div>
              </div>
            );
          })}
        </div>

        {/* Widget canvas */}
        {widgets.length===0?(
          <div className="card fade-in" style={{display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',minHeight:360,gap:16,borderStyle:'dashed'}}>
            <div style={{fontSize:48,opacity:.15}}>◈</div>
            <div style={{fontFamily:'var(--ff-h)',fontSize:18,fontWeight:700,color:'var(--t2)'}}>No widgets configured</div>
            <p style={{fontSize:13,color:'var(--t3)',textAlign:'center',maxWidth:380,lineHeight:1.7}}>
              Click <strong style={{color:'var(--t1)'}}>Configure Dashboard</strong> to add charts, KPI cards, and tables.
            </p>
            <button className="btn btn-primary" onClick={toggleEdit}>⚙ Configure Dashboard</button>
          </div>
        ):(
          <RGL layouts={layouts} breakpoints={BP} cols={COLS} rowHeight={60}
            isDraggable={false} isResizable={false}
            onLayoutChange={handleLayout} margin={[12,12]} containerPadding={[0,0]}>
            {widgets.map(w=>(
              <div key={w.id} style={{background:'#fff',borderRadius:'var(--r2)',border:'1px solid var(--border)',overflow:'hidden',boxShadow:'var(--s1)'}}>
                <WidgetRenderer widget={w}/>
              </div>
            ))}
          </RGL>
        )}
      </div>
    </div>
  );
}
